// Generate search suggestions from categories and subcategories
export const generateSearchSuggestions = (query) => {
  if (!query || query.length < 2) return [];
  
  const suggestions = [];
  const lowerQuery = query.toLowerCase();
  
  categoriesData.forEach(category => {
    // Check category name match
    if (category.name.toLowerCase().includes(lowerQuery)) {
      suggestions.push({
        type: 'category',
        name: category.name,
        icon: category.icon,
        id: category.id,
        categoryName: category.name,
        description: `Browse all ${category.name} artists`,
        fullPath: `${category.name}`,
        badge: 'Category'
      });
    }
    
    // Check subcategories and items with enhanced context
    category.subcategories.forEach(subcategory => {
      if (subcategory.name.toLowerCase().includes(lowerQuery)) {
        suggestions.push({
          type: 'subcategory',
          name: subcategory.name,
          icon: category.icon,
          categoryId: category.id,
          categoryName: category.name,
          subcategoryName: subcategory.name,
          description: `${subcategory.name} specialists in ${category.name}`,
          fullPath: `${category.name} → ${subcategory.name}`,
          badge: 'Subcategory'
        });
      }
      
      // Check individual items with full context
      subcategory.items.forEach(item => {
        if (item.toLowerCase().includes(lowerQuery)) {
          suggestions.push({
            type: 'item',
            name: item,
            icon: category.icon,
            categoryId: category.id,
            categoryName: category.name,
            subcategoryName: subcategory.name,
            itemName: item,
            description: `${item} artists in ${subcategory.name} ${category.name.toLowerCase()}`,
            fullPath: `${category.name} → ${subcategory.name} → ${item}`,
            badge: 'Skill'
          });
        }
      });
    });
  });
  
  // Sort by relevance (exact matches first, then partial)
  suggestions.sort((a, b) => {
    const aExact = a.name.toLowerCase() === lowerQuery;
    const bExact = b.name.toLowerCase() === lowerQuery;
    if (aExact && !bExact) return -1;
    if (!aExact && bExact) return 1;
    return a.name.localeCompare(b.name);
  });
  
  // Limit suggestions to 10 for better UX
  return suggestions.slice(0, 10);
};
